def test_train_demo_requires_api_key_when_configured(monkeypatch):
    """Reject training requests without X-API-Key when API_KEY is configured."""

    monkeypatch.setenv("API_KEY", "secret-key")
    monkeypatch.setenv("RATE_LIMIT_MAX", "60")
    monkeypatch.setenv("RATE_LIMIT_WINDOW_SECONDS", "60")
    _reset_runtime_state()

    client = TestClient(app)

    unauthorized = client.post("/train/demo?samples=200&segment_count=4")
    assert unauthorized.status_code == 401

    authorized = client.post(
        "/train/demo?samples=200&segment_count=4",
        headers={"X-API-Key": "secret-key"},
    )
    assert authorized.status_code == 200
    assert authorized.json()["status"] == "trained"


def test_write_endpoints_are_rate_limited(monkeypatch):
    """Return 429 when the same client exceeds configured request budget."""

    monkeypatch.setenv("API_KEY", "secret-key")
    monkeypatch.setenv("RATE_LIMIT_MAX", "2")
    monkeypatch.setenv("RATE_LIMIT_WINDOW_SECONDS", "300")
    _reset_runtime_state()

    client = TestClient(app)
    headers = {"X-API-Key": "secret-key"}

    first = client.post("/train/demo?samples=200&segment_count=4", headers=headers)
    second = client.post("/train/demo?samples=200&segment_count=4", headers=headers)
    third = client.post("/train/demo?samples=200&segment_count=4", headers=headers)

    assert first.status_code == 200
    assert second.status_code == 200
    assert third.status_code == 429


