def test_readiness_can_require_trained_model(monkeypatch):
    """Fail readiness until training when model requirement is enabled."""

    monkeypatch.delenv("API_KEY", raising=False)
    monkeypatch.setenv("REQUIRE_MODEL_FOR_READINESS", "true")
    _reset_runtime_state()

    client = TestClient(app)

    before_training = client.get("/health/readiness")
    assert before_training.status_code == 503
    assert before_training.json()["status"] == "not_ready"

    train_response = client.post("/train/demo?samples=200&segment_count=4")
    assert train_response.status_code == 200

    after_training = client.get("/health/readiness")
    assert after_training.status_code == 200
    assert after_training.json()["status"] == "ready"


def test_large_request_body_is_rejected(monkeypatch):
    """Reject oversized request payloads before endpoint execution."""

    monkeypatch.delenv("API_KEY", raising=False)
    monkeypatch.setenv("MAX_REQUEST_BYTES", "150")
    _reset_runtime_state()

    client = TestClient(app)
    large_payload = {"records": [_valid_record() for _ in range(30)]}

    response = client.post("/predict/activity", json=large_payload)

    assert response.status_code == 413
    assert response.json()["detail"] == "Request body too large."


